const a = $json;
const scores = a.scores || {};
const delta = a.delta || {};
const core30 = a.core30_coverage || {};

const deltaStr = (v) => v > 0 ? `+${v}` : v < 0 ? `${v}` : '—';

const dashboardUrl = `https://YOUR_DOMAIN/dashboard.html?locationId=${a.ghl_location_id}`;

const subject = `[Audit] ${a.business_name} — Score: ${scores.overall || '?'}/100 (${a.audit_date})`;

const body = `# Site Audit Report: ${a.business_name}
**${a.domain}** • ${a.target_city || ''}, ${a.target_state || ''} • ${a.audit_date}

## Scores
| Metric | Score | Change |
|--------|-------|--------|
| Overall | ${scores.overall || '—'} | ${deltaStr(delta.overall)} |
| SEO | ${scores.seo?.score || '—'} | ${deltaStr(delta.seo)} |
| AI | ${scores.ai_discoverability?.score || 'null'} | ${deltaStr(delta.ai_discoverability)} |
| GEO | ${scores.geo_readiness?.score || '—'} | ${deltaStr(delta.geo_readiness)} |

## Findings
- **${a.open_findings}** open findings
- **${a.critical_findings}** critical issues

## Core 30 Coverage
- Categories: ${core30.categories_found || 0}/${core30.categories_total || 0}
- Services: ${core30.services_found || 0}/${core30.services_total || 0}

[View Full Dashboard](${dashboardUrl})
`;

return [{ json: { subject, body, dashboardUrl, business_name: a.business_name, domain: a.domain, overall_score: scores.overall, critical_findings: a.critical_findings } }];
